import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Map;
import java.util.HashMap;

class Solution {
    /**
     * Returns an integer array ans, where ans[i] is the number of times queries[i]
     * appears as a word in s.
     *
     * @param chunks The string array to be concatenated.
     * @param queries The string array of queries.
     * @return The result array.
     */
    public static long[] solve(String[] chunks, String[] queries) {
        // 1. Concatenate chunks to form s
        StringBuilder sBuilder = new StringBuilder();
        for (String chunk : chunks) {
            sBuilder.append(chunk);
        }
        String s = sBuilder.toString();

        // 2. Tokenize s into words
        // A word is defined by non-alphanumeric/non-valid-hyphen characters acting as separators.
        // A valid word character is a lowercase letter or a hyphen surrounded by letters.
        // Non-word characters are anything that is NOT a lowercase letter or a hyphen.

        // We can iterate through s and identify contiguous segments that could be words.
        // The definition of a word is tricky: "it is not part of a longer word".
        // This implies we need to find maximal valid tokens.

        List<String> words = new ArrayList<>();
        int n = s.length();
        int i = 0;

        while (i < n) {
            // Skip separators (non-word characters)
            if (!isValidWordChar(s.charAt(i))) {
                i++;
                continue;
            }

            // Start of a potential word segment
            int start = i;
            int j = i;

            // Find the maximal segment consisting only of letters and valid hyphens
            while (j < n && isValidWordChar(s.charAt(j))) {
                j++;
            }

            String potentialToken = s.substring(start, j);

            // Now, we need to validate if this maximal token is a valid *word*
            // A token is a word if it adheres to the structure and is maximal.

            String word = validateAndNormalizeWord(potentialToken);

            if (!word.isEmpty()) {
                // Since we extracted the maximal segment satisfying local constraints,
                // and the definition says "it is not part of a longer subword",
                // this maximal segment itself is a word if it's structurally valid.
                // The validation logic below ensures this.
                words.add(word);
            }

            i = j; // Move to the next character after the potential token
        }

        // 3. Count frequencies of all words in s
        Map<String, Long> wordCounts = new HashMap<>();
        for (String word : words) {
            wordCounts.put(word, wordCounts.getOrDefault(word, 0L) + 1);
        }

        // 4. Answer queries
        long[] ans = new long[queries.length];
        for (int k = 0; k < queries.length; k++) {
            String query = queries[k];
            // The problem statement guarantees queries[i] is a valid word.
            ans[k] = wordCounts.getOrDefault(query, 0L);
        }

        return ans;
    }

    /**
     * Checks if a character is a lowercase letter or a hyphen that is validly placed.
     * Since we are tokenizing maximal segments first, we only check for structural validity 
     * within the segment context later. Here, we check if it's a letter or a hyphen.
     */
    private static boolean isValidWordChar(char c) {
        return (c >= 'a' && c <= 'z') || c == '-';
    }

    /**
     * Validates the structure of a token extracted from s to ensure it fits the word definition.
     * A word must be composed of 'a'-'z' and '-' only if surrounded by letters.
     * If it's structurally invalid (e.g., starts/ends with '-', or has '--'), it shouldn't be counted.
     * Since the problem guarantees queries are valid words, we primarily need to ensure 
     * our extraction process yields only maximal, structurally valid tokens.
     *
     * For this specific problem context, since we extract maximal segments of [a-z-], 
     * we must check the hyphen rules.
     * 
     * @param token The maximal sequence of [a-z-].
     * @return The canonical form of the word, or "" if invalid.
     */
    private static String validateAndNormalizeWord(String token) {
        if (token.isEmpty()) return "";

        // Check for structural validity based on hyphen rules:
        // 1. Must only contain [a-z] and '-'
        for (char c : token.toCharArray()) {
            if (!((c >= 'a' && c <= 'z') || c == '-')) {
                // This should ideally not happen if isValidWordChar is correct, but defensive check.
                return "";
            }
        }

        // 2. Hyphen constraints: must be surrounded by letters.
